        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[CancelReplaceRiskRequestMessage](sbeTemplateId=");
            builder.Append(CancelReplaceRiskRequestMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(CancelReplaceRiskRequestMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != CancelReplaceRiskRequestMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(CancelReplaceRiskRequestMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != CancelReplaceRiskRequestMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(CancelReplaceRiskRequestMessage.BlockLength);
            builder.Append("):");

            builder.Append("UserId=");
            builder.Append(this.UserId);
            builder.Append('|');
            builder.Append("RiskCheckId=");
            builder.Append(this.RiskCheckId);
            builder.Append('|');
            builder.Append("IsOpening=");
            builder.Append(this.IsOpening);
            builder.Append('|');
            builder.Append("Venue=");
            builder.Append(this.Venue);
            builder.Append('|');
            builder.Append("Side=");
            builder.Append(this.Side);
            builder.Append('|');
            builder.Append("Qty=");
            builder.Append(this.Qty);
            builder.Append('|');
            builder.Append("Price=");
            if (this.Price != null)
            {
                this.Price.BuildString(builder);
            }
            else
            {
                builder.Append("null");
            }
            builder.Append('|');
            builder.Append("Route=");
            builder.Append("'");
            for (int i = 0; i < RouteLength && this.GetRoute(i) > 0; ++i)
            {
                builder.Append((char)this.GetRoute(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("BaseStrategy=");
            builder.Append(this.BaseStrategy);
            builder.Append('|');
            builder.Append("StrikeSpacing=");
            builder.Append(this.StrikeSpacing);
            builder.Append('|');
            builder.Append("OrderId=");
            builder.Append("'");
            for (int i = 0; i < OrderIdLength && this.GetOrderId(i) > 0; ++i)
            {
                builder.Append((char)this.GetOrderId(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("SubmitTime=");
            builder.Append(this.SubmitTime);
            builder.Append('|');
            builder.Append("NewQty=");
            builder.Append(this.NewQty);
            builder.Append('|');
            builder.Append("NewPrice=");
            if (this.NewPrice != null)
