                this.NewPrice.BuildString(builder);
            }
            else
            {
                builder.Append("null");
            }
            builder.Append('|');
            builder.Append("NewRoute=");
            builder.Append("'");
            for (int i = 0; i < NewRouteLength && this.GetNewRoute(i) > 0; ++i)
            {
                builder.Append((char)this.GetNewRoute(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("UnderlyingSymbol=");
