            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("Description=");
            builder.Append('\'').Append(GetDescription()).Append('\'');
            builder.Append('|');
            builder.Append("Symbol=");
            builder.Append('\'').Append(GetSymbol()).Append('\'');

